template:
use std::f64::consts::PI;

#[derive(Debug)]
struct Circle {
    radius: f64,
}

impl Circle {
    fn circumference(&self) -> f64 {
        2.0 * PI * self.radius
    }

    [[SLOT ctor_sig]] {
        [[SLOT self_init]]
    }
}

fn main() {
    let c = [[SLOT ctor_call]];
    println!("{:?} has circumference {}", c, c.circumference());
}
